4	export function ResultsView({ results }: { results: WalletScanResult[] | null }) {
5	  if (results === null) {
6	    return (
7	      <p className="font-serif italic text-[var(--color-fg-faint)] text-center text-lg py-16">
8	        Nothing retrieved yet. Begin with a scan.
9	      </p>
10	    );
11	  }
12	  if (!results.length) {
13	    return (
14	      <p className="font-serif italic text-[var(--color-fg-faint)] text-center text-lg py-12">
15	        silence in the hall
16	      </p>
17	    );
18	  }
19	
20	  const totalKeys = results.reduce((s, r) => s + r.keys.length, 0);
21	  const totalSat = results.reduce(
22	    (s, r) => s + r.keys.reduce((a, k) => a + (k.balance_sat ?? 0), 0),
23	    0,
24	  );
25	  const withValue = results.filter((r) =>
26	    r.keys.some((k) => (k.balance_sat ?? 0) > 0),
27	  ).length;
28	
29	  return (
30	    <div>
31	      <div className="border border-[var(--color-rule)] px-5 py-4 mb-6 flex flex-wrap gap-x-8 gap-y-2">
32	        <Stat term="wallets" value={String(results.length)} />
33	        <Stat term="keys" value={String(totalKeys)} />
34	        <Stat term="with value" value={String(withValue)} hit />
35	        <Stat term="recovered" value={`${satToBtc(totalSat)} BTC`} hit />
36	      </div>
37	
38	      {results.map((r, i) => (
39	        <section
40	          key={`${r.source_file}-${i}`}
41	          className={cn(
42	            "py-5 border-t border-[var(--color-rule)] first:border-t-0 first:pt-0",
43	          )}
