1	import type { WalletScanResult, ExtractedKey, DecodedMnemonic, ScanSummary } from "@/types";
2	
3	const BASE = "/api";
4	
5	async function call<T>(path: string, init?: RequestInit): Promise<T> {
6	  const r = await fetch(`${BASE}${path}`, init);
7	  const text = await r.text();
8	  let body: unknown;
9	  try {
10	    body = text ? JSON.parse(text) : null;
11	  } catch {
12	    throw new Error(`Non-JSON from ${path}: ${text.slice(0, 200)}`);
13	  }
14	  if (!r.ok) {
15	    const msg =
16	      body && typeof body === "object" && "error" in body
17	        ? String((body as { error: unknown }).error)
18	        : r.statusText;
19	    throw new Error(msg);
20	  }
21	  return body as T;
22	}
23	
24	export interface ScanReply {
25	  results: WalletScanResult[];
26	  summary: ScanSummary;
27	}
28	
29	export async function scan(files: File[], passwords: string, provider: string): Promise<ScanReply> {
30	  const fd = new FormData();
31	  for (const f of files) fd.append("wallet", f);
32	  if (passwords) fd.append("passwords", passwords);
33	  fd.append("provider", provider);
34	  return call("/scan", { method: "POST", body: fd });
35	}
36	
37	export async function demo(): Promise<ScanReply> {
38	  return call("/demo", { method: "POST" });
39	}
40	
41	export async function mnemonic(payload: {
42	  phrase: string;
43	  kind: "bip39" | "blockchain";
44	  passphrase?: string;
45	  gap_limit?: number;
46	  wordlist?: string;
47	}): Promise<{ keys?: ExtractedKey[]; decoded?: DecodedMnemonic }> {
48	  return call("/mnemonic", {
49	    method: "POST",
50	    headers: { "Content-Type": "application/json" },
51	    body: JSON.stringify(payload),
52	  });
