import qrcode from "qrcode-generator";

export function QRCode({
  value,
  size = 128,
}: {
  value: string;
  size?: number;
}) {
  const qr = qrcode(0, "M");
  qr.addData(value);
  qr.make();

  const cells = qr.getModuleCount();
  const cellSize = size / cells;

  const rects: string[] = [];
  for (let y = 0; y < cells; y++) {
    for (let x = 0; x < cells; x++) {
      if (qr.isDark(y, x)) {
        rects.push(
          `<rect x="${x * cellSize}" y="${y * cellSize}" width="${cellSize}" height="${cellSize}" fill="currentColor"/>`,
        );
      }
    }
  }

  return (
    <svg
      width={size}
      height={size}
      viewBox={`0 0 ${size} ${size}`}
      role="img"
      aria-label={`QR code for ${value}`}
      className="text-[var(--color-text)] bg-white p-1 rounded"
      dangerouslySetInnerHTML={{ __html: rects.join("") }}
    />
  );
}
```

