```rust
use std::path::{Path, PathBuf};

pub(crate) fn validate_scan_path(raw: &str) -> Result<PathBuf, String> {
    if raw.starts_with('~') {
        return Err("paths starting with ~ are not allowed; resolve first".into());
    }
    let path = Path::new(raw);
    if !path.is_absolute() {
        return Err("path must be absolute".into());
    }
    // Canonicalize if possible; fall back to normalize manually.
    let resolved = match path.canonicalize() {
        Ok(p) => p,
        Err(_) => {
            // Path may not exist yet; reject ..
            if path.components().any(|c| matches!(c, std::path::Component::ParentDir)) {
                return Err("path may not contain ..".into());
            }
            path.to_path_buf()
        }
    };
    let home = dirs::home_dir().ok_or_else(|| "no HOME dir".to_string())?;
    if !resolved.starts_with(&home) {
        return Err(format!(
            "path must be inside {}",
            home.display()
        ));
    }
    Ok(resolved)
}
```

