        .map_err(|msg| axum::response::IntoResponse::into_response((axum::http::StatusCode::BAD_REQUEST, msg)))?;
    let passwords_vec: Vec<String> =
        body.passwords.lines().filter(|l| !l.is_empty()).map(String::from).collect();
    let provider_name = body.provider.unwrap_or_else(|| "blockstream".into());

    let results = tokio::task::spawn_blocking(move || {
        let provider: Option<Box<dyn orpheus_core::balance::BalanceProvider>> =
            match provider_name.as_str() {
                "blockstream" => Some(Box::new(orpheus_core::balance::BlockstreamProvider::default())),
                "blockchain" => Some(Box::new(orpheus_core::balance::BlockchainInfoProvider::default())),
                "mock" => Some(Box::new(orpheus_core::balance::MockProvider { path: None })),
                _ => None,
            };
        orpheus_core::scanner::scan_path(&resolved, &passwords_vec, provider.as_deref())
    })
    .await
    .map_err(|e| (axum::http::StatusCode::INTERNAL_SERVER_ERROR, e.to_string()))?;

    Ok(Json(ScanReply { results, summary: None }))
}
