    if (!phrase.trim()) {
      setErr("Paste a phrase first.");
      return;
    }
    setBusy(true);
    try {
      const body = await mnemonic({
        phrase: phrase.trim(),
        kind,
        passphrase,
        gap_limit: gapLimit,
        wordlist: wordlist.trim() || undefined,
