  return (
    <form onSubmit={onSubmit} className="flex flex-col gap-6 max-w-[720px]">
      <header>
        <h1 className="text-xl font-semibold m-0">
          Derive keys from a mnemonic
        </h1>
        <p className="text-sm text-[var(--color-text-dim)] mt-1">
